from kelvin.api.client import Client

    # Login
    client = Client(url="https://<url.kelvin.ai>", username="<your_username>")
    client.login(password="<your_password>")

    # Upload file to filestore
    response_csvfile = client.filestorage.upload_file(
        file='/home/ubuntu/publisher-example.csv', 
        metadata={"description": "Data required for the My CSV Publisher Connection."}
    )

    # Create Connection
    client.app_workloads.create_workload(data={
    "name":"docs-csv-publisher",
    "title":"Docs CSV Publisher",
